{"path":"~/.hermes/plugins/snapshot-router/__init__.py","content":"from __future__ import annotations

import json
import os
import subprocess
from pathlib import Path

STATE_FILE = Path.home() / ".hermes" / "snapshot-router.json"


def _projects_root() -> Path:
    return (Path.home() / "projects").resolve()


def _default_repo() -> Path:
    return (_projects_root() / "agent-orchestration-playbook").resolve()


def _load_state() -> dict:
    if STATE_FILE.exists():
        try:
            data = json.loads(STATE_FILE.read_text(encoding="utf-8"))
            if isinstance(data, dict):
                return data
        except Exception:
            pass
    return {"default_repo": str(_default_repo()), "bindings": {}}


def _session_binding_key() -> str:
    # Example: agent:main:discord:thread:1499717837626019921:1499717837626019921
    return os.getenv("HERMES_SESSION_KEY", "").strip()


def _resolve_from_override(project_override: str) -> Path:
    p = Path(project_override)
    if not p.is_absolute():
        p = _projects_root() / project_override
    return p.expanduser().resolve()


def _resolve_project_dir(raw_args: str) -> tuple[Path, str, list[str]]:
    raw = (raw_args or "").strip()
    project_override = ""
    topic = raw
    notes: list[str] = []

    # Syntax:
    # /snapshot-save dir=<name|/abs/path> your title/topic
    # /snapshot-save repo=<name|/abs/path> your title/topic  (alias)
    if raw.startswith("dir=") or raw.startswith("repo="):
        parts = raw.split(None, 1)
        head = parts[0]
        project_override = head.split("=", 1)[1].strip()
        topic = parts[1].strip() if len(parts) > 1 else ""

    state = _load_state()
    default_repo = Path(state.get("default_repo") or _default_repo()).expanduser().resolve()
    bindings = state.get("bindings") if isinstance(state.get("bindings"), dict) else {}

    # 1) explicit override wins
    if project_override:
        target = _resolve_from_override(project_override)
        key = _session_binding_key()
        bound = Path(bindings.get(key, "")).expanduser().resolve() if key and bindings.get(key) else None
        if bound and bound != target:
            notes.append(f"cross-repo override: bound={bound} override={target}")
        return target, (topic or "snapshot-save"), notes

    # 2) session binding
    key = _session_binding_key()
    if key and key in bindings:
        target = Path(bindings[key]).expanduser().resolve()
        return target, (topic or "snapshot-save"), notes

    # 3) cwd under ~/projects/<name>
    cwd = Path.cwd().resolve()
    projects = _projects_root()
    if projects in cwd.parents:
        project_dir = cwd
        while project_dir.parent != projects:
            project_dir = project_dir.parent
        return project_dir, (topic or "snapshot-save"), notes

    # 4) configured default_repo
    if default_repo.exists():
        notes.append("used default_repo fallback")
        return default_repo, (topic or "snapshot-save"), notes

    # 5) last resort inbox (never fail)
    inbox = (_projects_root() / "_local_inbox").resolve()
    notes.append("used _local_inbox fallback")
    return inbox, (topic or "snapshot-save"), notes


def _run_snapshot(raw_args: str) -> str:
    script = Path.home() / ".hermes" / "scripts" / "save-snapshot.py"
    if not script.exists():
        return f"❌ SCRIPT_MISSING: {script}"

    project_dir, topic, notes = _resolve_project_dir(raw_args)

    if not project_dir.exists():
        project_dir.mkdir(parents=True, exist_ok=True)

    payload = {
        "topic": topic,
        "summary": "Snapshot captured via /snapshot-save.",
        "context": "Project-scoped snapshot save with auto-routing.",
        "decisions": "Prefer session binding/cwd/default_repo; fallback to _local_inbox when needed.",
        "progress": "Snapshot command executed.",
        "open_questions": "none",
        "next_actions": "continue",
        "references": str(script),
    }

    cmd = ["python3", str(script), "--stdin-json", "--project-root", str(project_dir)]
    try:
        proc = subprocess.run(
            cmd,
            input=json.dumps(payload, ensure_ascii=False),
            capture_output=True,
            text=True,
            check=True,
        )
        out = proc.stdout.strip()
        data = json.loads(out) if out else {}
        if data.get("ok"):
            extra = ""
            if notes:
                extra = "\n- notes: " + " | ".join(notes)
            return (
                "✅ snapshot saved\n"
                f"- path: {data.get('path')}\n"
                f"- title: {data.get('title')}\n"
                f"- topic: {data.get('topic')}\n"
                f"- redaction_hits: {data.get('redaction_hits')}\n"
                f"- project: {data.get('project_root')}\n"
                f"- detected_mode: {data.get('detected_mode')}"
                f"{extra}"
            )
        return f"❌ snapshot failed: {out or proc.stderr.strip() or 'unknown error'}"
    except subprocess.CalledProcessError as e:
        msg = e.stderr.strip() or e.stdout.strip() or str(e)
        return f"❌ snapshot failed: {msg}"
    except Exception as e:
        return f"❌ snapshot failed: {e}"


def register(ctx):
    ctx.register_command(
        "snapshot-save",
        handler=_run_snapshot,
        description="Save snapshot with auto project routing + local fallback",
        args_hint="dir=<name|/abs/path> optional title",
    )
"}

